/// HTTP method

#[wasm_bindgen]
#[derive(Clone, Copy, PartialEq, Eq)]
pub enum WasmMethod {
    Get = 0,
    Post = 1,
    Put = 2,
    Patch = 3,
    Delete = 4,
    Head = 5,
    Options = 6,
    Trace = 7,
}

#[allow(clippy::derivable_impls)]
impl Default for WasmMethod {
    fn default() -> Self {
        Self::Get
    }
}

impl WasmMethod {
    /// Returns the serde wire string for this variant (e.g. `"stop"`, `"tool_calls"`).
    pub fn to_api_str(self) -> &'static str {
        match self {
            Self::Get => "Get",
            Self::Post => "Post",
            Self::Put => "Put",
            Self::Patch => "Patch",
            Self::Delete => "Delete",
            Self::Head => "Head",
            Self::Options => "Options",
            Self::Trace => "Trace",
        }
    }

    /// Parses a serde wire string and returns the corresponding variant, or None if unrecognized.
    pub fn from_api_str(s: &str) -> Option<Self> {
        match s {
            "Get" => Some(Self::Get),
            "Post" => Some(Self::Post),
            "Put" => Some(Self::Put),
            "Patch" => Some(Self::Patch),
            "Delete" => Some(Self::Delete),
            "Head" => Some(Self::Head),
            "Options" => Some(Self::Options),
            "Trace" => Some(Self::Trace),
            _ => None,
        }
    }
}

