impl From<WasmSecuritySchemeInfo> for spikard_http::SecuritySchemeInfo {
    fn from(val: WasmSecuritySchemeInfo) -> Self {
        match val.r#type.as_str() {
            "http" => Self::Http {
                scheme: val.scheme.clone().unwrap_or_default(),
                bearer_format: val.bearer_format.clone(),
            },
            "apiKey" => Self::ApiKey {
                location: val.location.clone().unwrap_or_default(),
                name: val.name.clone().unwrap_or_default(),
            },
            _ => Self::Http {
                scheme: Default::default(),
                bearer_format: Default::default(),
            },
        }
    }
}

impl From<spikard_http::SecuritySchemeInfo> for WasmSecuritySchemeInfo {
    fn from(val: spikard_http::SecuritySchemeInfo) -> Self {
        match val {
            spikard_http::SecuritySchemeInfo::Http { scheme, bearer_format } => Self {
                r#type: "http".to_string(),
                bearer_format,
                location: None,
                name: None,
                scheme: Some(scheme),
            },
            spikard_http::SecuritySchemeInfo::ApiKey { location, name } => Self {
                r#type: "apiKey".to_string(),
                bearer_format: None,
                location: Some(location),
                name: Some(name),
                scheme: None,
            },
        }
    }
}
